from typing import Annotated
import operator
from langgraph.types import Send

class State(TypedDict):
    items: list[str]
    scored: Annotated[list[dict], operator.add]   # reducer required

def router(state: State):
    # Emit one Send per item; LangGraph parallelizes them.
    return [Send("score_one", {"item": x}) for x in state["items"][:20]]

def score_one(payload):
    # Idempotent: same input → same output, no external mutation.
    return {"scored": [{"item": payload["item"], "score": llm_score(payload["item"])}]}

def router(state: State):
    return [Send("write_row", {"id": x}) for x in state["items"]]   # 200 sends

def write_row(payload):
    db.update(payload["id"], status="processed")                    # side effect
    return {"done": [payload["id"]]}
